const input = $input.first().json;
const headers = input.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
const token = authHeader.replace('Bearer ', '');
const query = input.query || {};

if (!token) {
  return [{ json: { success: false, error: '로그인이 필요합니다' } }];
}

try {
  const payload = JSON.parse(Buffer.from(token, 'base64').toString());
  if (payload.exp && payload.exp < Date.now()) {
    return [{ json: { success: false, error: '세션이 만료되었습니다' } }];
  }
  return [{ json: { userId: payload.userId, limit: query.limit || '20' } }];
} catch(e) {
  return [{ json: { success: false, error: '유효하지 않은 토큰입니다' } }];
}

const raw = $input.first().json;
let data = raw;
if (typeof raw.data === 'string') { try { data = JSON.parse(raw.data); } catch(e) {} }
let orders = [];
if (data.list && Array.isArray(data.list)) {
  orders = data.list;
} else if (data && typeof data === 'object') {
  orders = Object.values(data).filter(v => typeof v === 'object' && v !== null && (v.ord_no || v.order_no));
}

const items = orders.map(o => {
  let status = 'pending';
  const state = String(o.ord_state || o.order_status || '');
  if (state === '2' || state === '3') status = 'confirmed';
  else if (state === '4') status = 'preparing';
  else if (state === '5') status = 'shipped';
  else if (state === '6') status = 'delivered';
  else if (state === '7' || state === '8') status = 'cancelled';

  const img = o.prd_image || o.product_image || '';
  return {
    id: o.ord_no || o.order_no || '',
    orderNo: o.ord_no || o.order_no || '',
    date: o.ord_date || o.order_date || '',
    status,
    totalPrice: parseInt(o.ord_price || o.order_price || '0'),
    productName: o.prd_name || o.product_name || '',
    productImage: img.startsWith('http') ? img : img ? 'https://foreverlove.co.kr' + img : '',
    trackingNumber: o.inv_no || '',
    trackingUrl: o.inv_no ? 'https://trace.cjlogistics.com/web/detail.jsp?slipno=' + o.inv_no : '',
  };
}).filter(o => o.id);

return [{ json: { success: true, data: items, total: items.length } }];
